import { supabase } from '../lib/supabase'

export type LearningHistoryInsert = {
  owner: string
  repo: string
  path: string
  sha: string
  line_no: number
  type: 'pass' | 'fail' | 'fin'
  duration: number
}

export type LearningHistoryRow = LearningHistoryInsert & {
  id: number
  user_id: string
  created_at: string
}

export async function addLearningHistories(
  items: LearningHistoryInsert[],
  userId?: string
): Promise<void> {
  const finalUserId = userId || (await supabase.auth.getUser()).data.user?.id
  if (!finalUserId) throw new Error('Not authenticated')

  const rows = items.map((item) => ({
    ...item,
    user_id: finalUserId,
  }))

  const { error } = await supabase.from('learning_histories').insert(rows)
  if (error) throw error
}

export async function getLearningHistoriesBySha(
  sha: string,
  userId?: string
): Promise<LearningHistoryRow[]> {
  let query = supabase
    .from('learning_histories')
    .select('*')
    .eq('sha', sha)
    .order('created_at', { ascending: true })

  if (userId) {
    query = query.eq('user_id', userId)
  }

  const { data, error } = await query

  if (error) throw error
  return data ?? []
}

export async function getLearningHistoriesByDirectory(
  owner: string,
  repo: string,
  path?: string,
  userId?: string
): Promise<LearningHistoryRow[]> {
  let query = supabase
    .from('learning_histories')
    .select('*')
    .eq('owner', owner)
    .eq('repo', repo)
    .eq('type', 'fin')
    .order('created_at', { ascending: true })

  if (path) {
    query = query.like('path', `${path}%`)
  }

  if (userId) {
    query = query.eq('user_id', userId)
  }

  const { data, error } = await query
  if (error) throw error
  return data ?? []
}

export async function getAllLearningHistories(userId?: string): Promise<LearningHistoryRow[]> {
  let query = supabase
    .from('learning_histories')
    .select('*')
    .order('created_at', { ascending: false })

  if (userId) {
    query = query.eq('user_id', userId)
  }

  const { data, error } = await query
  if (error) throw error
  return data ?? []
}
